1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface QuoteItem {
6	  type: string;
7	}
8	
9	export interface QuoteStep {
10	  op: "quote";
11	  items: QuoteItem[];
12	}
13	
14	export type Step = QuoteStep;
15	
16	export interface Scenario {
17	  customer: Customer;
18	  steps: Step[];
19	}
20	
21	export interface QuoteResult {
22	  premium: number;
23	}
24	
25	export type StepResult = QuoteResult;
26	
27	export interface ScenarioResult {
28	  results: StepResult[];
29	}
30	
31	const basePremiums: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const PROCESSING_FEE = 5;
41	
42	const BLOCK_SIZE = 3;
43	
44	const BLOCK_OF_THREE_BASE = 60;
45	
46	const componentTypes = new Set(["rune", "moonstone"]);
47	
48	const countByType = (items: QuoteItem[]): Record<string, number> =>
49	  items.reduce<Record<string, number>>((counts, item) => {
50	    counts[item.type] = (counts[item.type] ?? 0) + 1;
51	    return counts;
52	  }, {});
53	
54	const basePremiumForGroup = (type: string, count: number): number => {
55	  if (componentTypes.has(type) && count === BLOCK_SIZE) {
56	    return BLOCK_OF_THREE_BASE;
57	  }
58	  return basePremiums[type] * count;
59	};
60	
61	const sumOfBasePremiums = (items: QuoteItem[]): number => {
62	  const counts = countByType(items);
63	  return Object.entries(counts).reduce(
64	    (sum, [type, count]) => sum + basePremiumForGroup(type, count),
65	    0
66	  );
67	};
68	
69	export function runScenario(scenario: Scenario): ScenarioResult {
70	  const results = scenario.steps.map((step) => {
71	    const basePremium = sumOfBasePremiums(step.items);
72	    return { premium: basePremium + PROCESSING_FEE };
73	  });
74	  return { results };
75	}
